$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Дні зберігання статистики з’єднань';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Рядки старші за це значення буде видалено з connections, connections_source і connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Введіть кількість днів, протягом яких потрібно зберігати сирі статистичні дані відвідувачів PrestaShop. Приклад: 60 означає, що модуль зберігає останні 60 днів і видаляє старіші записи з ps_connections, ps_connections_source і ps_connections_page. Не встановлюйте 1, якщо не впевнені, що вам не потрібна недавня статистика.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Розмір пакета';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Максимальна кількість з’єднань, оброблених в одному пакеті.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Введіть, скільки основних записів з’єднань можна обробити в одному внутрішньому пакеті. Менші значення безпечніші на слабкому хостингу, але потребують більше запусків cron. Більші значення очищають швидше, але можуть довше утримувати блокування бази даних. Рекомендоване початкове значення: 1000–5000; збільшуйте лише після тестування часу виконання.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Максимум пакетів за запуск';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Обмежує обсяг роботи одного запуску cron.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Введіть, скільки пакетів може виконуватися під час одного запуску cron. Можлива загальна кількість видалених основних записів за запуск приблизно дорівнює Розмір пакета помножено на Максимум пакетів за запуск. Приклад: 5000 і 10 означає до приблизно 50000 записів за один запуск cron. Зменште це значення, якщо магазин сповільнюється під час очищення.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Очистити ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Очищає кеш блоку фасетного/layered пошуку за допомогою TRUNCATE TABLE. Таблиця повторно створюється MySQL/MariaDB порожньою.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Увімкніть лише якщо ps_layered_filter_block надто зростає або містить застарілий кеш фасетного пошуку. Це не видаляє товари, категорії чи індекс layered-цін. Після очищення PrestaShop або модуль фасетного пошуку може відновити кеш за потреби.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Агрегувати статистику джерел трафіку перед видаленням';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Зберігає щоденну підсумкову статистику джерел трафіку перед видаленням сирих рядків.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Якщо увімкнено, модуль зберігає невеликий щоденний підсумок перед видаленням сирої статистики PrestaShop. Він зберігає кількість відвідувань, переглядів сторінок, домен джерела та UTM-значення. IP-адреси, повні referrer URL або рядки user-agent не зберігаються. Вимкніть, якщо потрібне лише видалення без історичних підсумків.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Дні зберігання агрегованої статистики';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Як довго зберігати невелику щоденну таблицю підсумків.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Введіть, скільки днів агреговані підсумки джерел трафіку мають залишатися в таблиці модуля. Приклад: 730 зберігає приблизно два роки щоденних підсумків. Це налаштування стосується лише таблиці ps_jooim_dbcleaner_traffic_daily, а не оригінальних статистичних таблиць PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Тайм-аут застарілого блокування в секундах';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Захист від одночасного запуску двох процесів очищення.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2c1824ea38ec688698a26f01a46e6b16'] = 'Введіть кількість секунд, після яких незавершене блокування очищення вважається покинутим. Це захищає базу даних від двох одночасних запусків cron. Рекомендоване значення: 7200. Зменшуйте лише якщо cron гарантовано завершується швидко.';
